content:
{
  "sentences": [
    {
      "text": "我的公寓有一個客廳和兩個房間。",
      "pinyin": "Wǒ de gōngyù yǒu yī ge kètīng hé liǎng ge fángjiān.",
      "pinyin_numeric": "wo3 de gong1yu4 you3 yi1 ge4 ke4ting1 he2 liang3 ge4 fang2jian1.",
      "translation_en": "My apartment has one living room and two rooms.",
      "translation_ko": "제 아파트에는 거실 하나와 방 두 개가 있습니다."
    },
    {
      "text": "房間裡有一張床和一個衣櫃。",
      "pinyin": "Fángjiān lǐ yǒu yī zhāng chuáng hé yī ge yīguì.",
      "pinyin_numeric": "fang2jian1 li3 you3 yi1 zhang1 chuang2 he2 yi1 ge4 yi1gui4.",
      "translation_en": "There is a bed and a wardrobe in the room.",
      "translation_ko": "방 안에는 침대 하나와 옷장 하나가 있습니다."
    },
    {
      "text": "客廳有沙發、桌子和電視。",
      "pinyin": "Kètīng yǒu shāfā, zhuōzi hé diànshì.",
      "pinyin_numeric": "ke4ting1 you3 sha1fa1, zhuo1zi5 he2 dian4shi4.",
      "translation_en": "The living room has a sofa, a table, and a TV.",
      "translation_ko": "거실에는 소파, 테이블, 텔레비전이 있습니다."
    },
    {
      "text": "廚房有水槽、冰箱和熱水器。",
      "pinyin": "Chúfáng yǒu shuǐcáo, bīngxiāng hé rèshuǐqì.",
      "pinyin_numeric": "chu2fang2 you3 shui3cao2, bing1xiang1 he2 re4shui3qi4.",
      "translation_en": "The kitchen has a sink, a refrigerator, and a water heater.",
      "translation_ko": "부엌에는 싱크대, 냉장고, 온수기가 있습니다."
    },
    {
      "text": "浴室有馬桶、水龍頭和一個窗戶。",
      "pinyin": "Yùshì yǒu mǎtǒng, shuǐlóngtóu hé yī ge chuānghù.",
      "pinyin_numeric": "yu4shi4 you3 ma3tong3, shui3long2tou2 he2 yi1 ge4 chuang1hu4.",
      "translation_en": "The bathroom has a toilet, a faucet, and a window.",
      "translation_ko": "욕실에는 변기, 수도꼭지, 창문 하나가 있습니다."
    },
    {
      "text": "陽台有洗衣機和一個小桌子。",
      "pinyin": "Yángtái yǒu xǐyījī hé yī ge xiǎo zhuōzi.",
      "pinyin_numeric": "yang2tai2 you3 xi3yi1ji1 he2 yi1 ge4 xiao3 zhuo1zi5.",
      "translation_en": "The balcony has a washing machine and a small table.",
      "translation_ko": "발코니에는 세탁기와 작은 테이블이 있습니다."
    },
    {
      "text": "房間沒有冷氣，但是有電風扇。",
      "pinyin": "Fángjiān méiyǒu lěngqì, dànshì yǒu diànfēngshàn.",
      "pinyin_numeric": "fang2jian1 mei2you3 leng3qi4, dan4shi4 you3 dian4feng1shan4.",
      "translation_en": "The room doesn't have air conditioning, but it has an electric fan.",
      "translation_ko": "방에는 에어컨이 없지만 선풍기가 있습니다."
    },
    {
      "text": "客廳的牆壁有兩個插座和一個開關。",
      "pinyin": "Kètīng de qiángbì yǒu liǎng ge chāzuò hé yī ge kāiguān.",
      "pinyin_numeric": "ke4ting1 de5 qiang2bi4 you3 liang3 ge4 cha1zuo4 he2 yi1 ge4 kai1guan1.",
      "translation_en": "The living room wall has two outlets and one switch.",
      "translation_ko": "거실 벽에는 콘센트 두 개와 스위치 하나가 있습니다."
    },
    {
      "text": "公寓的門有鎖，可是鑰匙不見了。",
      "pinyin": "Gōngyù de mén yǒu suǒ, kěshì yàoshi bùjiàn le.",
      "pinyin_numeric": "gong1yu4 de5 men2 you3 suo3, ke3shi4 yao4shi5 bu4jian4 le5.",
      "translation_en": "The apartment door has a lock, but the key is missing.",
      "translation_ko": "아파트 문에는 자물쇠가 있지만 열쇠가 없어졌습니다."
    },
    {
      "text": "房間的地板很乾淨，天花板有燈。",
      "pinyin": "Fángjiān de dìbǎn hěn gānjìng, tiānhuābǎn yǒu dēng.",
      "pinyin_numeric": "fang2jian1 de5 di4ban3 hen3 gan1jing4, tian1hua1ban3 you3 deng1.",
      "translation_en": "The room's floor is very clean, and the ceiling has a light.",
      "translation_ko": "방 바닥은 매우 깨끗하고 천장에는 등이 있습니다."
    }
  ]
}
